#include<bits/stdc++.h>
using namespace std;
struct milk
{
	int money,num;
};
bool fun(milk a,milk b)
{
	return a.money<b.money;
}
milk a[5005];
int main()
{
	int n,m,ans=0;
	cin>>n>>m;
	for(int i=0;i<=m-1;i++)
	{
		int x,y;
		cin>>x>>y;
		a[i].money=x;
		a[i].num=y;
	}
	sort(a,a+m,fun);
	for(int i=0;i<=m-1;i++)
	{
		if(n>=a[i].num)
		{
			n-=a[i].num;
			ans=ans+a[i].money*a[i].num;
		}
		else
		{
			n-=a[i].num;
			ans=ans+a[i].money * n;
		}
		if(n<=0) 
		{
			cout<<ans;
			return 0;
		}
	}
	return 0;
}
